object QuerryS3T {

import zadscripts.DFScripts
import scala.collection.mutable.ArrayBuffer
import scala.math.BigDecimal
import org.apache.spark.sql.types.DecimalType

val s3 = new DFScripts 

def s3TQuerry(rLow:String,rHigh:String,nMax:String,d1:String,d2:String,d3:String,tC:Int): ArrayBuffer[s3TQu] = {

val terms = new ArrayBuffer[s3TQu]()
//val s3 = new DFScripts  
val s3RS = s3.s3T(rLow,rHigh,nMax,d1,d2,d3,tC)

while (s3RS.next()) {
terms += s3TQu(s3RS.getString(1),s3RS.getString(2),s3RS.getString(3),s3RS.getString(4),s3RS.getString(5),s3RS.getString(6),s3RS.getString(7))
}
terms
}

def main(args:Array[String]) {

//type TTupple = Tuple2[ArrayBuffer[s3TQu],BigDecimal]   // Don't think this tupple is being used.
val terms = new ArrayBuffer[ArrayBuffer[s3TQu]]()
val nMax = "10000"                                 
for(a <- 6 to 6; n <- 14 to 14;b <- 0 to (n-2)) {
     terms += QuerryS3T.s3TQuerry(n.toString,n.toString,nMax,BigDecimal(2).pow(a).toString(),BigDecimal(2).pow(a).toString(),BigDecimal(2).pow(a).toString(),BigDecimal(2).pow(b).toInt)
}

val mainTermss=terms.flatMap(_.toList)

val df = spark.createDataFrame(mainTermss)
val dfCount = df.count()
df.show(dfCount.toInt,false)
z.put("s12DF",df)
}
}
